-- In-session → Goal-Setting Phase scenario — Happy Path
-- Stable keys map to fixed UUIDs in src/data/goalSettingHappyPathFallback.ts

update public.service_scenarios
set
  description = 'Tutors guide students through goal setting in breakout sessions.',
  view_type = 'side-by-side'
where id = 'a0000000-0000-4000-8000-000000000204';

values (
  'a0000000-0000-4000-8000-00000000080c',
  'a0000000-0000-4000-8000-000000000204',
  'Happy Path',
  'General overview of tutors guiding students through goal-setting activities in breakout sessions. For a more detailed look at the activities, see the other paths in this scenario.',
  'happy'
)
on conflict (id) do update set
  service_scenario_id = excluded.service_scenario_id,
  name = excluded.name,
  description = excluded.description,
  path_type = excluded.path_type;

delete from public.cell_triggers
where source_cell_id in (
  select id from public.cells
  where path_id = 'a0000000-0000-4000-8000-00000000080c'
);

delete from public.cells
where path_id = 'a0000000-0000-4000-8000-00000000080c';

delete from public.layers
where path_id = 'a0000000-0000-4000-8000-00000000080c';

on conflict (id) do update set
  name = excluded.name,
  row_position = excluded.row_position,
  path_id = excluded.path_id;

on conflict (id) do update set
  name = excluded.name,
  service_scenario_id = excluded.service_scenario_id;

delete from public.path_steps
where path_id = 'a0000000-0000-4000-8000-00000000080c';

on conflict (path_id, step_id) do update set
  column_position = excluded.column_position;

on conflict (id) do update set
  path_id = excluded.path_id,
  layer_id = excluded.layer_id,
  step_id = excluded.step_id,
  content = excluded.content;

update public.cells
set picture = '/blueprint-images/goal-setting/happy-path/regular-tutor/step-01-join-breakout-session.png'
where id = 'a0000000-0000-4000-8000-0000001a0103';

update public.cells
set picture = '/blueprint-images/goal-setting/happy-path/regular-tutor/step-02-share-screen.png'
where id = 'a0000000-0000-4000-8000-0000001a0203';

on conflict (id) do update set
  source_cell_id = excluded.source_cell_id,
  target_cell_id = excluded.target_cell_id;

update public.cells
set links = (
  select coalesce(
    jsonb_agg(
      case
        when link->>'label' = 'PLUS App' then
          link || jsonb_build_object(
            'description',
            'The tutor fills out the update, check, or set goals modal in the PLUS app with the student.'
          )
        else link
      end
    ),
    '[]'::jsonb
  )
  from jsonb_array_elements(coalesce(links, '[]'::jsonb)) as link
)
where id = 'a0000000-0000-4000-8000-0000001a0306';

update public.cells
set links = (
  select coalesce(
    jsonb_agg(
      case
        when link->>'label' = 'PLUS App' then
          link || jsonb_build_object(
            'description',
            'If prompted, the tutor fills out the goal achievement strategy form in the PLUS app with the student.'
          )
        else link
      end
    ),
    '[]'::jsonb
  )
  from jsonb_array_elements(coalesce(links, '[]'::jsonb)) as link
)
where id = 'a0000000-0000-4000-8000-0000001a0406';

update public.cells
set content = E'Dev Team\nDesign Team',
    description =
      'Dev Team builds the app and the Design Team creates the screens and flows relevant to this step. Both implement the findings from the research team into the app in their respective role.'
where id in (
  'a0000000-0000-4000-8000-0000001a0209',
  'a0000000-0000-4000-8000-0000001a0309',
  'a0000000-0000-4000-8000-0000001a0409',
  'a0000000-0000-4000-8000-0000001a0509',
  'a0000000-0000-4000-8000-0000001a0709'
);
